  // For self-multiply (square), the result is always non-negative
  if (SelfMultiply) {
    Known.makeNonNegative();

    // If squaring a sign-extended value, we can compute tighter bounds
    // based on the original bit width before extension
    if (auto *SExt = dyn_cast<SExtInst>(Op0)) {
      unsigned SrcBitWidth = SExt->getSrcTy()->getScalarSizeInBits();
      unsigned DstBitWidth = Known.getBitWidth();

      // Maximum absolute value after sign extension from SrcBitWidth
      // is 2^(SrcBitWidth-1), so maximum square is 2^(2*SrcBitWidth-2)
      if (2 * SrcBitWidth - 2 < DstBitWidth) {
        unsigned LeadingZeros = DstBitWidth - (2 * SrcBitWidth - 2) - 1;
        Known.Zero.setHighBits(LeadingZeros);
